<template>
  <div class="settings">
    <h3>Настройки</h3>
    <div class="welcome">
      <div></div>
      Добро пожаловать
    </div>
    <DarkThemeVue />
    <button @click="handleSignOut" class="registerBtn" v-if="isLoggedIn">
      Выйти
    </button>
    <router-link to="/register" class="registerBtn" v-else
      >Зарегистрироваться</router-link
    >
  </div>
</template>

<script setup>
import { onMounted, ref } from "vue";
import { getAuth, onAuthStateChanged, signOut } from "firebase/auth";
import router from "@/router";
import DarkThemeVue from "@/components/DarkTheme/DarkTheme.vue";

const isLoggedIn = ref(false);
let auth;
function scriptLoad(url, fn) {
  fn = fn || function () {};
  var a = document.createElement("script");
  a.src = url;
  a.onload = fn;
  a.onreadystatechange = fn;
  document.head.appendChild(a);
}
onMounted(() => {
  scriptLoad("//code.jivo.ru/widget/nU6sMUQGuS");
  auth = getAuth();
  onAuthStateChanged(auth, (user) => {
    const photo = user.photoURL;
    const userName = user.email;
    document.querySelector(".welcome").innerHTML += `<span>${userName}</span>`;
    document.querySelector(
      ".welcome > div"
    ).innerHTML += `<img src="${photo}">`;
    console.log(photo);
    if (user) {
      isLoggedIn.value = true;
    } else {
      isLoggedIn.value = false;
    }
  });
});
const handleSignOut = () => {
  signOut(auth).then(() => {
    router.push("/sign-in");
  });
};
</script>
