<template>
  <div class="neumorphism-toggle">
    <input type="checkbox" id="darkTheme" />
    <label for="darkTheme" @click="darkThemeToggler()">
      <span><i class="fas fa-sun" :class="darkTheme == false ? 'active' : ''"></i></span>
      <div class="switch" @click="darkTheme = !darkTheme">
        <div class="dot"></div>
      </div>
      <span><i class="fas fa-moon" :class="darkTheme ? 'active' : ''"></i></span>
    </label>
  </div>
</template>
<style scoped>
.switch{
    margin: 0 10px;
}
span{
    margin: 0 10px !important;
}
i{
    transition: .3s ease;
}
i.active{
    color: #ecee68 !important;
}
.neumorphism-toggle input + label{
    padding: 16px 20px !important;
}
</style>
<script>
import "./DarkTheme.scss";
export default {
  name: "dark-theme",
  data() {
    return {
      darkTheme: false,
    };
  },
  methods: {
    darkThemeToggler() {
      const body = document.querySelector("body");
      body.classList.toggle("dark-theme");
    },
  },
};
</script>
